<?php if(!class_exists('Rain\Tpl')){exit;}?><div class="content-wrapper"><section class="content-header painel-topo"><h1><i class="bi bi-shield-lock"></i> Permissões por Perfil<small>Gerencie ACL por perfil</small></h1></section><section class="content"><form method="post" action="/admin/seguranca/permissoes"><div class="card mb-4 painel-formulario"><div class="card-header cabecalho-formulario"><div class="card-title">Matriz de Permissões</div></div><div class="card-body"><?php $counter1=-1;  if( isset($permissions) && ( is_array($permissions) || $permissions instanceof Traversable ) && sizeof($permissions) ) foreach( $permissions as $key1 => $value1 ){ $counter1++; ?><div class="row mb-2"><div class="col-md-4"><strong><?php echo htmlspecialchars( $value1["module_name"], ENT_COMPAT, 'UTF-8', FALSE ); ?></strong> - <?php echo htmlspecialchars( $value1["description"], ENT_COMPAT, 'UTF-8', FALSE ); ?><br><small class="text-muted"><?php echo htmlspecialchars( $value1["permission_key"], ENT_COMPAT, 'UTF-8', FALSE ); ?></small></div><div class="col-md-8"><label class="me-3"><input type="checkbox" name="permissions[ADMIN][]" value="<?php echo htmlspecialchars( $value1["permission_key"], ENT_COMPAT, 'UTF-8', FALSE ); ?>" <?php if( in_array($value1["permission_key"], $admin_permissions) ){ ?>checked<?php } ?>> ADMIN</label><label class="me-3"><input type="checkbox" name="permissions[SUPERVISOR][]" value="<?php echo htmlspecialchars( $value1["permission_key"], ENT_COMPAT, 'UTF-8', FALSE ); ?>" <?php if( in_array($value1["permission_key"], $supervisor_permissions) ){ ?>checked<?php } ?>> SUPERVISOR</label><label><input type="checkbox" name="permissions[ASSESSOR][]" value="<?php echo htmlspecialchars( $value1["permission_key"], ENT_COMPAT, 'UTF-8', FALSE ); ?>" <?php if( in_array($value1["permission_key"], $assessor_permissions) ){ ?>checked<?php } ?>> ASSESSOR</label></div></div><hr><?php } ?></div><div class="card-footer"><button class="btn btn-primary" type="submit">Salvar Permissões</button></div></div></form></section></div>